function Metric({ to, cap, accent, prefix = '', suffix = '' }: { to: number; cap: string; accent?: boolean; prefix?: string; suffix?: string }) {
  const ref = useRef<HTMLDivElement>(null)
  const [val, setVal] = useState(0)
  const [started, setStarted] = useState(false)

  useEffect(() => {
    const el = ref.current
    if (!el) return
    const obs = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting && !started) {
        setStarted(true)
        obs.disconnect()
        if (to === 0) { setVal(0); return }
        const duration = 1100
        const start = performance.now()
        const tick = (now: number) => {
          const p = Math.min((now - start) / duration, 1)
          const eased = 1 - Math.pow(1 - p, 3) // easeOutCubic
          setVal(Math.round(to * eased))
          if (p < 1) requestAnimationFrame(tick)
        }
        requestAnimationFrame(tick)
      }
    }, { threshold: 0.4 })
    obs.observe(el)
    return () => obs.disconnect()
  }, [to, started])

  return (
    <div className="maya-metric" ref={ref}>
      <div className={`maya-metric-fig${accent ? ' accent' : ''}`}>{prefix}{val}{suffix}</div>
      <div className="maya-metric-cap">{cap}</div>
    </div>
  )
}

function Faq({ q, a }: { q: string; a: string }) {
  const [open, setOpen] = useState(false)
  return (
    <div className="maya-faq-item">
      <button onClick={() => setOpen(o => !o)} className="maya-faq-q">
        <span>{q}</span>
        <span className="maya-faq-sign">{open ? '–' : '+'}</span>
      </button>
      {open && <p className="maya-faq-a">{a}</p>}
    </div>
  )
}

